@app.errorhandler(RedisError)
def handle_redis_error(err: RedisError):
    logger.exception("Redis error: %s", err)
    return jsonify({"error": "redis_error", "message": str(err)}), 503


@app.errorhandler(Exception)
def handle_exception(err: Exception):
    logger.exception("Unhandled error: %s", err)
    return jsonify({"error": "internal_server_error", "message": "Unexpected error"}), 500


@app.get("/health")
def health():
    try:
        ok = cache_service.ping()
        return jsonify({"status": "ok" if ok else "degraded"}), 200 if ok else 503
    except RedisError as err:
        logger.exception("Health check failed: %s", err)
        return jsonify({"status": "down", "error": str(err)}), 503


